mapper.select:
SELECT ID, WAREHOUSE_IN_TITLE, WAREHOUSE_IN_NO, WAREHOUSE_IN_TYPE_CODE, WAREHOUSE_IN_TYPE_NAME, WAREHOUSE_IN_DATE, DEPT_ID, DEPT_NAME, WAREHOUSE_ID, WAREHOUSE_NAME, SUPPLIER_ID, SUPPLIER_NAME, REMARKS, DELIVERY_PERSON_ID, DELIVERY_PERSON_NAME, ACCEPTANCE_PERSON_ID, ACCEPTANCE_PERSON_NAME, ACCEPTANCE_STATUS, ACCEPTANCE_REMARKS, BATCH_NO, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME FROM E_MATERIAL_WAREHOUSE_IN
AND WAREHOUSE_IN_NO LIKE #{warehouseInNoPattern}
AND WAREHOUSE_IN_TITLE LIKE #{warehouseInTitlePattern}
AND SUPPLIER_NAME LIKE #{supplierNamePattern}
AND WAREHOUSE_IN_TYPE_CODE = #{warehouseInTypeCode}
AND DEPT_ID = #{deptId}
AND WAREHOUSE_ID = #{warehouseId}
AND ACCEPTANCE_STATUS = #{acceptanceStatus}
ORDER BY CREATE_TIME DESC

SELECT COUNT(*)
FROM E_MATERIAL_WAREHOUSE_IN
WHERE WAREHOUSE_IN_NO = #{warehouseInNo}

    AND ID != #{id}
